import Typewriter from "typewriter-effect"
import styled from "styled-components"

import { useInView } from 'react-intersection-observer';

const Projects = ({ id }) => {
  const { ref, inView, entry } = useInView({
    /* Optional options */
    threshold: 0,
    triggerOnce: true
  });

  return (
    <ProjectsContainer id={id}>
      {/* <Typewriter
        onInit={(typewriter) => {
          typewriter
            .changeDelay(80)
            .typeString("Projects")
            .pauseFor(1000)
            .callFunction(state => state.elements.cursor.style.display = "none")
            .start()
        }} */}
          <div ref={ref}>

            <Typewriter
              onInit={(typewriter) => {
                typewriter
                  .changeDelay(80)
                  .typeString("Projects")
                  .pauseFor(1000)
                  .callFunction(state => state.elements.cursor.style.display = "none")
                  .start()
              }}
            />
          </div>
    </ProjectsContainer>
  )
}

const ProjectsContainer = styled.section`
  width: 100%;
  height: 100vh;

  color: white;
  font-size: 3em;
`

export default Projects
